# frozen_string_literal: true

require "verse/core"

module Http
  module Gen
    module Template
      extend Verse::Util::StringUtil

      module_function

      HEADER = strip_indent <<-RUBY
        # API Autogenerated. DO NOT EDIT
        # Generated at %<time>s
        # frozen_string_literal: true

        Api.create_domain :%<domain>s, base_path: "api/v3/%<domain>s"

      RUBY

      METHOD_TEMPLATE = strip_indent <<-RUBY
        %<description>s
        Api.add_to_domain :%<domain>s, :%<method_name>s do |data, headers: {}|
          path = %<path>s
          final_path = path.dup

          if data.is_a?(Hash)
            # Remove optional path segments if not present on data
            path.scan(/(\\\(\\/?%%{\\w+}\\/?\\)\\?)/) do
              result = $1
              match = result.match(/\\/?%%{(\\w+)}\\/?/)
              final_path.gsub!(result, data[match[1].to_sym] ? match[0] : "")
            end

            # Replace path segments with data
            final_path %%= data

            # Delete data existing in path:
            path.scan(/%%{(\\w+)}/) do
              data.delete($1.to_sym)
            end
          end

          %<headers>s

          auth = %<auth>s

          %<pre_process_script>s
          output = %<call>s
          %<post_process_script>s
        end

      RUBY

      CALLS = {
        get: "get(final_path, query: data, headers:, auth:)",
        post: "post(final_path, body: data, headers:, auth:)",
        put: "put(final_path, body: data, headers:, auth:)",
        patch: "patch(final_path, body: data, headers:, auth:)",
        delete: "delete(final_path, headers:, auth:)"
      }.freeze

      POST_PROCESSES = {
        "Verse::JsonApi::Renderer" => "deserialize(output)",
        "Verse::Http::Renderer::Json" => "JSON.parse(output)"
      }.freeze

      VND_JSON = %("application/vnd.api+json")

      JSON_API_HEADERS = %(headers = headers.merge({ "Accept" => #{VND_JSON}, "Content-Type" => #{VND_JSON} })).freeze

      JSON_RENDERER_HEADERS = %(
        headers = headers.merge({
          "Accept"       => "application/json",
          "Content-Type" => "application/json"
        })
      )

      HEADERS = {
        "Verse::JsonApi::Renderer" => JSON_API_HEADERS,
        "Verse::Http::Renderer::Json" => JSON_RENDERER_HEADERS
      }.freeze

      PRE_PROCESSES = {
        "Verse::JsonApi::Renderer" => "data = data.to_json",
        "Verse::Http::Renderer::Json" => "data = data.to_json"
      }.freeze

      def exposition_name(exposition_class)
        # Remove "Expo::" from the class name
        exposition_class.to_s.split("::")[1..].map(&method(:underscore)).join("_")
      end

      def generate
        domain = Verse.service_name.to_sym

        nil_auth_strategy = Verse::Http::Auth.get(nil)

        output = String.new
        output << format(HEADER, time: Time.now, domain:)

        Verse::Exposition::Base.all_expositions.each do |expo|
          expo.exposed_endpoints.each do |method_name, data|
            hook = data[:type]

            next unless hook.is_a?(Verse::Http::Exposition::Hook)

            path = hook.path.gsub(/:(\w+)/, '%{\1}').inspect
            http_method = hook.http_method

            method_name = [method_name, exposition_name(expo)].join("_")

            post_process_script = ""
            if http_method == :delete
              post_process_script = "output.nil? ? nil : "
            end
            post_process_script += POST_PROCESSES.fetch(hook.renderer.to_s, "output")

            pre_process_script = ""
            unless http_method == :get # GET body don't need to be pre-processed
              pre_process_script = PRE_PROCESSES.fetch(hook.renderer.to_s, "")
            end

            auth = hook.auth != nil_auth_strategy ? "true" : "false"

            description = strip_indent(hook.metablock.desc || ":nodoc:").chomp.split("\n").map do |x|
              "  # #{x}".strip
            end.join("\n")

            headers = HEADERS.fetch(hook.renderer.to_s, "")

            args = {
              domain:,
              method_name:,
              headers:,
              description:,
              path:,
              call: CALLS.fetch(http_method),
              post_process_script:,
              pre_process_script:,
              auth:
            }

            output << (METHOD_TEMPLATE % args).gsub(/(\n[ \t]*)+$/, "\n") << "\n"
          end
        end

        output.chomp
      end
    end
  end
end
